// `defer` is NOT a reserved word — `import defer from "x"` must
// still parse as an ordinary default import. So: treat `defer`
// as a phase keyword ONLY when the very next token is `*`.
if default_name_raw == b"defer"
    && p.lexer.token == T::TAsterisk
    && !opts.is_export
{
    p.lexer.next()?;
    p.lexer.expect_contextual_keyword(b"as")?;
    stmt = S::Import {
        namespace_ref: p.store_name_in_ref(p.lexer.identifier)?,
        phase_defer: true,
        ..Default::default()
    };
    return p.process_import_statement(stmt, path, loc, false);
}

